B.ar=new A.y3(0,"hazard")
B.MJ=new A.bH("Accord Patrol Checkpoint","A patrol frigate flags your transponder. Standard inspection costs time and fuel.",B.ar,0,-4,0,0,0,0,0,0,0)
B.HL=s([B.MJ],t.d)
B.cx=new A.y3(1,"bonus")
B.MN=new A.bH("Emergency Supply Cache","An Accord waypoint beacon is broadcasting. The sealed cache inside is still good.",B.cx,0,3,10,0,0,0,0,0,0)
B.II=s([B.MN],t.d)
B.MZ=new A.bH("Scattered Debris Field","Hull plating takes minor impacts crossing the outer belt. Nothing catastrophic \u2014 yet.",B.ar,-5,0,0,0,0,0,0,0,0)
B.MU=new A.bH("Drifter Supply Pod","A pressurized container tumbles out of the field. The scavenger code on the side has been scratched off.",B.cx,0,0,5,0,12,0,0,0,0)
B.Hd=s([B.MZ,B.MU],t.d)
B.hB=new A.y3(2,"intel")
B.MI=new A.bH("Chithari Scout Formation","Three alien scouts shadow your jump before peeling away. They know you're here.",B.hB,0,0,0,0,0,0,0,0,5)
B.MS=new A.bH("Drive Thermal Vents","Residual radiation from the old war zone destabilizes your jump drive briefly.",B.ar,-4,-7,0,0,0,0,0,0,0)
B.Hm=s([B.MI,B.MS],t.d)
B.MB=new A.bH("Debris Impact","A hull fragment from a destroyed cruiser strikes your forward plating at speed.",B.ar,-8,0,0,0,0,0,0,0,0)
B.MP=new A.bH("Abandoned Cargo Container",'Pressurized and still sealed. The manifest inside reads: "Priority Accord Shipment \u2014 Do Not Open." You open it.',B.cx,0,0,0,0,18,10,0,0,0)
B.Ir=s([B.MB,B.MP],t.d)
B.MF=new A.bH("Ion Electrical Storm","The storm comes with no warning. Power stutters across every system. You ride it out.",B.ar,-10,-6,0,0,0,0,0,0,0)
B.MR=new A.bH("Distress Signal","Old, looping, probably automated. But the supply pod attached to the beacon is real.",B.cx,0,0,8,0,0,0,8,0,0)
B.I4=s([B.MF,B.MR],t.d)
B.MG=new A.bH("Ionized Fuel Pocket","Your nav system picks up a dense ionized pocket. A quick scoop nets usable fuel.",B.cx,0,6,0,0,0,0,0,0,0)
B.GK=s([B.MG],t.d)
B.N0=new A.bH("Dense Debris Cloud","Navigation at half-speed through the thickest part of the old battle zone.",B.ar,-6,-3,0,0,0,0,0,0,0)
B.Gl=s([B.N0],t.d)
B.MO=new A.bH("Electromagnetic Anomaly","Sensors go dark for eleven minutes. When they come back, crew morale has slipped.",B.ar,0,0,0,-4,0,0,0,0,6)
B.Hk=s([B.MO],t.d)
B.MC=new A.bH("Wraith Squadron Intercept","Eight unidentified fighters appear on approach. They hold formation \u2014 and fire twice. You take the hit and run.",B.ar,-15,0,0,0,0,-12,0,0,10)
B.MD=new A.bH("Old War Relics","A derelict carrier from the first Chithari contact drifts past. Its vault is cracked open.",B.cx,0,0,0,0,25,0,0,3,0)
B.Go=s([B.MC,B.MD],t.d)
B.N_=new A.bH("Keth'ari Resonance Burst","An alien resonance pulse scrambles your ship's sensors and stresses the O2 lines. Crew reports headaches.",B.ar,-5,0,0,-10,0,0,0,0,8)
B.MM=new A.bH("Abandoned Mining Station","Long-evacuated, but life support modules are intact. The O2 scrubbers are worth more than the rest of the ship combined.",B.cx,0,0,0,12,0,0,6,0,0)
B.I3=s([B.N_,B.MM],t.d)
B.MQ=new A.bH("Accord Escort Redeployment","An escort wing meets you and then pulls away on new orders. Your crew is not reassured.",B.ar,0,0,0,0,0,0,0,-4,5)
B.Mz=new A.bH("Accord Supply Request",'"Commander \u2014 Vanguard requisitions ten rations for the forward post. It\'s not a request." You comply.',B.ar,0,0,-10,0,0,0,0,3,0)
B.IW=s([B.MQ,B.Mz],t.d)
B.MH=new A.bH("The Void Silence","No signals, no ships, no debris. Nothing for eleven hours. The silence gets into your crew.",B.ar,0,0,0,0,0,0,0,-5,9)
B.MV=new A.bH("Hull Micro-fracture Event","The pressure differential catches a hairline crack in the outer plating. Emergency patch holds \u2014 barely.",B.ar,-16,0,0,-9,0,0,0,0,0)
B.Gn=s([B.MH,B.MV],t.d)
B.nY=s([],t.d)
B.MT=new A.bH("Chithari Interdiction Fleet","A full alien interdiction wing drops out of FTL directly in your path. You fight through. The cost is severe.",B.ar,-22,0,0,-6,0,-18,0,0,15)
B.ME=new A.bH("Final Approach Barricade",'Accord military cordon. They board, they inspect, they take what they want. "Security protocols," they say.',B.ar,0,0,-12,0,-15,0,0,0,0)
B.MK=new A.bH("Crew at the Breaking Point",'After the gauntlet, your crew sits in silence. One of them says: "We made it." Nobody argues.',B.hB,0,0,0,0,0,0,0,5,-8)
B.IN=s([B.MT,B.ME,B.MK],t.d)
B.My=new A.bH("Escort Wing Recalled","Your escort breaks formation on new orders. You are told nothing. The comms go silent.",B.ar,0,0,0,0,0,0,0,0,8)
B.MY=new A.bH("Priority Command Channel","Accord Command broadcasts directly to your bridge. The message is clear: arrive clean. Arrive correct.",B.hB,0,0,0,0,0,0,0,-3,4)
B.MX=new A.bH("Final Security Levy",'Automated Accord tollgate. Credits deducted without authorization. The receipt says "processing fee."',B.ar,0,0,0,0,-20,0,0,0,0)
B.HJ=s([B.My,B.MY,B.MX],t.d)
B.MW=new A.bH("The Long Empty Burn","Forty hours through open space with no navigational landmarks. Every system nominal. Crew stress is not.",B.ar,0,-8,0,-10,0,0,0,0,7)
